from flask import Flask, request, jsonify
from functools import wraps
import sqlite3

app = Flask(__name__)

DATABASE = 'tokens.db'

def get_db():
    conn = sqlite3.connect(DATABASE)
    return conn

# Initialize database and token table
def init_db():
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('''CREATE TABLE IF NOT EXISTS tokens (token TEXT PRIMARY KEY)''')
    conn.commit()
    conn.close()

init_db()

def token_exists(token):
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute("SELECT token FROM tokens WHERE token = ?", (token,))
    result = cursor.fetchone()
    conn.close()
    return result is not None

def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token or not token.startswith("Bearer "):
            return jsonify({"error": "Unauthorized"}), 401
        
        token = token.split(" ")[1]
        if not token_exists(token):
            return jsonify({"error": "Invalid Token"}), 403
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/secure-endpoint')
@require_oauth
def secure_endpoint():
    return jsonify({"message": "This is a secure endpoint with valid access token"})

@app.route('/register-token', methods=['POST'])
def register_token():
    new_token = request.json.get('token')
    conn = get_db()
    cursor = conn.cursor()
    try:
        cursor.execute("INSERT INTO tokens (token) VALUES (?)", (new_token,))
        conn.commit()
        return jsonify({"message": "Token registered successfully"}), 201
    except sqlite3.IntegrityError:
        return jsonify({"error": "Token already exists"}), 400
    finally:
        conn.close()

